import{_ as s,o as a,c as i,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Recursos rutas y metodos","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/apis-rest/02-recursos-rutas-y-metodos.md","filePath":"full-stack/arquitectura/apis-rest/02-recursos-rutas-y-metodos.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/apis-rest/02-recursos-rutas-y-metodos.md"};function n(d,e,c,l,r,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="recursos-rutas-y-metodos" tabindex="-1">Recursos rutas y metodos <a class="header-anchor" href="#recursos-rutas-y-metodos" aria-label="Permalink to &quot;Recursos rutas y metodos&quot;">​</a></h1><p>El diseno de rutas es una de las partes mas visibles de una API. Una ruta buena comunica el modelo mental del sistema.</p><h2 id="recursos" tabindex="-1">Recursos <a class="header-anchor" href="#recursos" aria-label="Permalink to &quot;Recursos&quot;">​</a></h2><p>Un recurso es una cosa del dominio que se puede identificar.</p><p>Ejemplos:</p><ul><li><code>/users</code></li><li><code>/orders</code></li><li><code>/products</code></li><li><code>/invoices</code></li><li><code>/projects</code></li></ul><p>Usa sustantivos, no verbos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bien: /orders</span></span>
<span class="line"><span>Mal:  /getOrders</span></span></code></pre></div><h2 id="colecciones-e-items" tabindex="-1">Colecciones e items <a class="header-anchor" href="#colecciones-e-items" aria-label="Permalink to &quot;Colecciones e items&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /orders          lista pedidos</span></span>
<span class="line"><span>POST /orders         crea pedido</span></span>
<span class="line"><span>GET /orders/{id}     obtiene pedido</span></span>
<span class="line"><span>PATCH /orders/{id}   modifica parcialmente</span></span>
<span class="line"><span>DELETE /orders/{id}  elimina o desactiva</span></span></code></pre></div><h2 id="recursos-anidados" tabindex="-1">Recursos anidados <a class="header-anchor" href="#recursos-anidados" aria-label="Permalink to &quot;Recursos anidados&quot;">​</a></h2><p>Usalos cuando la relacion sea parte natural del acceso.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /orders/{orderId}/items</span></span>
<span class="line"><span>POST /orders/{orderId}/items</span></span>
<span class="line"><span>DELETE /orders/{orderId}/items/{itemId}</span></span></code></pre></div><p>Evita anidamiento excesivo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/companies/{companyId}/departments/{departmentId}/teams/{teamId}/users/{userId}</span></span></code></pre></div><p>Si una ruta es demasiado profunda, quizas necesitas filtros:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /users?companyId=1&amp;teamId=8</span></span></code></pre></div><h2 id="metodos-http" tabindex="-1">Metodos HTTP <a class="header-anchor" href="#metodos-http" aria-label="Permalink to &quot;Metodos HTTP&quot;">​</a></h2><ul><li><code>GET</code>: leer sin efectos secundarios.</li><li><code>POST</code>: crear o ejecutar una accion no idempotente.</li><li><code>PUT</code>: reemplazar un recurso completo.</li><li><code>PATCH</code>: modificar parcialmente.</li><li><code>DELETE</code>: eliminar, cancelar o desactivar segun contrato.</li></ul><h2 id="acciones-de-dominio" tabindex="-1">Acciones de dominio <a class="header-anchor" href="#acciones-de-dominio" aria-label="Permalink to &quot;Acciones de dominio&quot;">​</a></h2><p>No fuerces todo a CRUD si el negocio tiene transiciones claras.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /orders/{id}/confirm</span></span>
<span class="line"><span>POST /orders/{id}/cancel</span></span>
<span class="line"><span>POST /invoices/{id}/send</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Las rutas usan sustantivos.</li><li>Los metodos tienen significado HTTP correcto.</li><li>Las acciones de negocio son explicitas.</li><li>Los identificadores son estables.</li><li>La profundidad de rutas se mantiene razonable.</li></ul>`,24)])])}const m=s(t,[["render",n]]);export{h as __pageData,m as default};
